  "index.quiz.pi.notSureResult.consult": { en: "One free consultation could reveal options you didn't know you had. Takes 30 seconds. Worst case — you learn exactly where you stand.", es: "Una consulta gratis podría revelar opciones que no sabía que tenía. Toma 30 segundos. En el peor caso — sabrá exactamente dónde se encuentra." },
  "index.quiz.pi.notSureResult.freeNote": { en: "Free. No obligation. Takes 30 seconds.", es: "Gratis. Sin compromiso. Toma 30 segundos." },

