  // INDEX — FAQ
  "index.faq.badge": { en: "Yes, We Already Know What You're Thinking", es: "Sí, Ya Sabemos Lo Que Está Pensando" },
  "index.faq.headline1": { en: "The Questions You're", es: "Las Preguntas Que" },
  "index.faq.headline2": { en: "Googling at", es: "Busca en Google a las" },
  "index.faq.headline3": { en: "2 A.M.", es: "2 A.M." },
  "index.faq.subtitle": { en: "If it's been keeping you up, it's probably in here.", es: "Si le ha quitado el sueño, probablemente está aquí." },
  "index.faq.q1": { en: "Can my employer fire me for filing workers' comp in Georgia?", es: "¿Puede mi empleador despedirme por presentar compensación laboral en Georgia?" },
  "index.faq.a1": { en: "Georgia is an 'at-will' state. But your workers' comp claim exists independently of your employment. Even if they fire you, Darwin will fight for every dollar you're entitled to.", es: "Georgia es un estado 'a voluntad'. Pero su reclamación de compensación laboral existe independientemente de su empleo. Aunque lo despidan, Darwin luchará por cada dólar al que tiene derecho." },
  "index.faq.q2": { en: "How much does it cost? I can barely pay my bills.", es: "¿Cuánto cuesta? Apenas puedo pagar mis facturas." },
  "index.faq.a2": { en: "Not one dime upfront. Darwin gets paid only if he wins or settles your case. If you don't get paid, he doesn't get paid. Zero risk.", es: "Ni un centavo por adelantado. Darwin solo cobra si gana o resuelve su caso. Si usted no cobra, él no cobra. Cero riesgo." },
  "index.faq.q3": { en: "How long until I get a settlement?", es: "¿Cuánto tiempo hasta que reciba un acuerdo?" },
  "index.faq.a3": { en: "It depends on injury severity and how aggressively the insurance company fights. Darwin files hearing requests immediately. Most clients see resolution within months, not years.", es: "Depende de la gravedad de la lesión y cuán agresivamente pelee la compañía de seguros. Darwin presenta solicitudes de audiencia inmediatamente. La mayoría de los clientes ven resolución en meses, no años." },
  "index.faq.q4": { en: "Do I even have a case?", es: "¿Siquiera tengo un caso?" },
  "index.faq.a4": { en: "If you were hurt performing your job duties, you very likely have a valid claim. Workers' comp is no-fault — you don't need to prove your employer did anything wrong.", es: "Si se lastimó realizando sus tareas laborales, es muy probable que tenga una reclamación válida. La compensación laboral es sin culpa — no necesita probar que su empleador hizo algo mal." },
  "index.faq.q5": { en: "Why Darwin instead of a big firm?", es: "¿Por qué Darwin en vez de una firma grande?" },
  "index.faq.a5": { en: "At bigger firms, you're a number. At Darwin's office, you talk to Darwin. He answers his own phone. 10,000+ cases, $250M+ recovered, and he still gives every client personal attention.", es: "En firmas más grandes, usted es un número. En la oficina de Darwin, usted habla con Darwin. Él contesta su propio teléfono. 10,000+ casos, $250M+ recuperados, y aún le da a cada cliente atención personal." },
  "index.faq.q6": { en: "The insurance company already made me an offer.", es: "La compañía de seguros ya me hizo una oferta." },
  "index.faq.a6": { en: "Don't sign anything. The first offer is designed to close your case cheap. Darwin has seen clients receive 5-10x more than the initial offer.", es: "No firme nada. La primera oferta está diseñada para cerrar su caso barato. Darwin ha visto clientes recibir 5-10x más que la oferta inicial." },

