  "wc.proof.recovered": { en: "Recovered for clients", es: "Recuperado para clientes" },
  "wc.proof.cases": { en: "Cases handled", es: "Casos manejados" },
  "wc.proof.courts": { en: "In Georgia courts", es: "En tribunales de Georgia" },
