  "thanks.headline": { en: "YOUR CALL WITH DARWIN IS CONFIRMED.", es: "SU LLAMADA CON DARWIN ESTÁ CONFIRMADA." },
  "thanks.subtitle": { en: "You will receive a confirmation shortly. Darwin will review your information before the call so you can get straight to what matters.", es: "Recibirá una confirmación en breve. Darwin revisará su información antes de la llamada para que puedan ir directo a lo que importa." },
  "thanks.beforeCall": { en: "BEFORE YOUR CALL", es: "ANTES DE SU LLAMADA" },
  "thanks.threeThings": { en: "Three Things to Have Ready.", es: "Tres Cosas Para Tener Listas." },
  "thanks.item1.title": { en: "The date and location of your injury or accident", es: "La fecha y lugar de su lesión o accidente" },
  "thanks.item1.sub": { en: "Even an approximate date is fine.", es: "Incluso una fecha aproximada está bien." },
  "thanks.item2.title": { en: "Any doctor's notes, reports, or medical records", es: "Notas del doctor, reportes, o registros médicos" },
  "thanks.item2.sub": { en: "Photos of the injury or accident scene if available.", es: "Fotos de la lesión o la escena del accidente si están disponibles." },
  "thanks.item3.title": { en: "Name of your employer or the other party involved", es: "Nombre de su empleador o la otra parte involucrada" },
  "thanks.item3.sub": { en: "This helps Darwin understand your situation before the call.", es: "Esto ayuda a Darwin a entender su situación antes de la llamada." },
  "thanks.dontWorry": { en: "Don't worry if you don't have everything. Darwin will walk you through it on the call.", es: "No se preocupe si no tiene todo. Darwin lo guiará durante la llamada." },
  "thanks.darwinQuote": { en: "I will review your situation personally. By the end of our call, you will know exactly where you stand. No pressure. No obligation. Just answers.", es: "Revisaré su situación personalmente. Al final de nuestra llamada, sabrá exactamente dónde se encuentra. Sin presión. Sin compromiso. Solo respuestas." },
  "thanks.reschedule": { en: "Need to reschedule or have a question?", es: "¿Necesita reprogramar o tiene una pregunta?" },
  "thanks.pickUp": { en: "Darwin or his team will pick up.", es: "Darwin o su equipo contestará." },

